// StrictServerInterface represents all server handlers.
type StrictServerInterface interface {
	// Search the external book catalog
	// (GET /books/search)
	SearchBooks(ctx context.Context, request SearchBooksRequestObject) (SearchBooksResponseObject, error)
	// Complete Google OAuth login
	// (GET /google/callback)
	GoogleCallback(ctx context.Context, request GoogleCallbackRequestObject) (GoogleCallbackResponseObject, error)
	// Start Google OAuth login
	// (GET /google/login)
	GoogleLogin(ctx context.Context, request GoogleLoginRequestObject) (GoogleLoginResponseObject, error)
	// List the current user's library
	// (GET /library)
	ListLibrary(ctx context.Context, request ListLibraryRequestObject) (ListLibraryResponseObject, error)
	// Add a catalog book to the current user's library
	// (POST /library)
	AddLibraryItem(ctx context.Context, request AddLibraryItemRequestObject) (AddLibraryItemResponseObject, error)
	// Remove a book from the current user's library
	// (DELETE /library/{id})
	DeleteLibraryItem(ctx context.Context, request DeleteLibraryItemRequestObject) (DeleteLibraryItemResponseObject, error)
	// Get one current-user library item
	// (GET /library/{id})
	GetLibraryItem(ctx context.Context, request GetLibraryItemRequestObject) (GetLibraryItemResponseObject, error)
	// Update one current-user library item
	// (PATCH /library/{id})
	PatchLibraryItem(ctx context.Context, request PatchLibraryItemRequestObject) (PatchLibraryItemResponseObject, error)
	// Delete the current session
	// (POST /logout)
	Logout(ctx context.Context, request LogoutRequestObject) (LogoutResponseObject, error)
	// Get the current authenticated user
	// (GET /me)
	GetMe(ctx context.Context, request GetMeRequestObject) (GetMeResponseObject, error)
}

type StrictHandlerFunc = strictnethttp.StrictHTTPHandlerFunc
type StrictMiddlewareFunc = strictnethttp.StrictHTTPMiddlewareFunc

type StrictHTTPServerOptions struct {
	RequestErrorHandlerFunc  func(w http.ResponseWriter, r *http.Request, err error)
	ResponseErrorHandlerFunc func(w http.ResponseWriter, r *http.Request, err error)
}

func NewStrictHandler(ssi StrictServerInterface, middlewares []StrictMiddlewareFunc) ServerInterface {
	return &strictHandler{ssi: ssi, middlewares: middlewares, options: StrictHTTPServerOptions{
		RequestErrorHandlerFunc: func(w http.ResponseWriter, r *http.Request, err error) {
			http.Error(w, err.Error(), http.StatusBadRequest)
		},
		ResponseErrorHandlerFunc: func(w http.ResponseWriter, r *http.Request, err error) {
			http.Error(w, err.Error(), http.StatusInternalServerError)
		},
	}}
}

func NewStrictHandlerWithOptions(ssi StrictServerInterface, middlewares []StrictMiddlewareFunc, options StrictHTTPServerOptions) ServerInterface {
	return &strictHandler{ssi: ssi, middlewares: middlewares, options: options}
}

type strictHandler struct {
	ssi         StrictServerInterface
	middlewares []StrictMiddlewareFunc
	options     StrictHTTPServerOptions
}

// SearchBooks operation middleware
func (sh *strictHandler) SearchBooks(w http.ResponseWriter, r *http.Request, params SearchBooksParams) {
	var request SearchBooksRequestObject

	request.Params = params

	handler := func(ctx context.Context, w http.ResponseWriter, r *http.Request, request interface{}) (interface{}, error) {
		return sh.ssi.SearchBooks(ctx, request.(SearchBooksRequestObject))
	}
	for _, middleware := range sh.middlewares {
		handler = middleware(handler, "SearchBooks")
	}

	response, err := handler(r.Context(), w, r, request)

	if err != nil {
		sh.options.ResponseErrorHandlerFunc(w, r, err)
	} else if validResponse, ok := response.(SearchBooksResponseObject); ok {
		if err := validResponse.VisitSearchBooksResponse(w); err != nil {
			sh.options.ResponseErrorHandlerFunc(w, r, err)
		}
	} else if response != nil {
		sh.options.ResponseErrorHandlerFunc(w, r, fmt.Errorf("unexpected response type: %T", response))
	}
}

